import{_ as o,o as t,c as i,ae as r}from"./chunks/framework.BD9pLfSD.js";const p=JSON.parse('{"title":"Execution Plan: Noir ZK Integration","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/branch_noir_integration.md","filePath":"docs/plans/branch_noir_integration.md"}'),a={name:"docs/plans/branch_noir_integration.md"};function n(l,e,c,s,d,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="execution-plan-noir-zk-integration" tabindex="-1">Execution Plan: Noir ZK Integration <a class="header-anchor" href="#execution-plan-noir-zk-integration" aria-label="Permalink to &quot;Execution Plan: Noir ZK Integration&quot;">​</a></h1><p><strong>Branch:</strong> <code>branch-noir-integration</code><strong>Parent:</strong> <code>branch-core-program</code><strong>Last Updated:</strong> 2026-01-21</p><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Replace the mock verification in <code>xb77_gateway</code> with real Noir proof verification using the <code>agent_badge</code> circuit.</p><h2 id="strategy-architecture-separation-implemented" tabindex="-1">Strategy: Architecture Separation (Implemented) <a class="header-anchor" href="#strategy-architecture-separation-implemented" aria-label="Permalink to &quot;Strategy: Architecture Separation (Implemented)&quot;">​</a></h2><p>To resolve severe dependency conflicts (Rust 2024 requirements in <code>blake3</code>/<code>verifier-lib</code> vs legacy Solana SBF toolchain), we have separated concerns:</p><ol><li><strong>Standalone Verifier Program (<code>verifier_program</code>)</strong>: <ul><li>Contains the heavy ZK logic (<code>verifier-lib</code>, <code>arkworks</code>).</li><li>Compiles in a dedicated Docker container (<code>xb77-solana-builder</code>) with modern Rust/Solana toolchain.</li><li>Exposes a simple instruction interface to verify proofs.</li></ul></li><li><strong>Gateway Program (<code>xb77_gateway</code>)</strong>: <ul><li>Remains lightweight and compatible with standard SBF build.</li><li>Invokes <code>verifier_program</code> via CPI to verify proofs.</li><li>Passes <code>[proof_len | proof | witness]</code> to the verifier.</li></ul></li></ol><h2 id="current-status-success" tabindex="-1">Current Status (Success) <a class="header-anchor" href="#current-status-success" aria-label="Permalink to &quot;Current Status (Success)&quot;">​</a></h2><ul><li><strong>Circuit</strong>: Complete.</li><li><strong>Verifier Program</strong>: Implemented and compiling in Docker.</li><li><strong>Gateway</strong>: Cleaned up and compiling locally. Calls Verifier via CPI.</li><li><strong>Tooling</strong>: <code>scripts/build-verifier-docker.sh</code> and <code>containers/builder</code> created.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ol><li><strong>Deploy &amp; Init</strong>: Run full deployment sequence on localnet.</li><li><strong>Demo</strong>: Verify end-to-end flow with <code>demo-private-order.sh</code>.</li><li><strong>Documentation</strong>: Update README with the new architecture instructions.</li></ol><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li><code>verifier_program.so</code> (Docker build).</li><li><code>xb77_gateway.so</code> (Local build).</li><li>Integrated <code>verify_badge</code> flow via CPI.</li></ul>',13)])])}const g=o(a,[["render",n]]);export{p as __pageData,g as default};
